parameters.text:
=Сообщение пользователя:
{{ $('Все данные').item.json.text }}

Дата, время:
{{ $now.setLocale('ru').toFormat('d MMMM yyyy, HH:mm') }}

Пользователь:
{{ $('Выбор опросника по чату и имени').item.json.name }}

parameters.jsCode:
const text = $input.first().json.output; // Поле с ответом от нейросети
const maxLength = 4000;
const parts = [];

for (let i = 0; i < text.length; i += maxLength) {
  parts.push({
    json: {
      chunk: text.substring(i, i + maxLength),
      partNumber: (i / maxLength) + 1
    }
  });
}

return parts;

// 1. Словарь чатов (объект JS)
const chatsName = {
  "249503190": "Проверка",
  "-1002209929376": "Опросник AlexLenaAI",
  "-1003878473296": "Замковая гора"
};

// 2. Берем первый элемент из входящей ноды
const item = $input.first().json;

// 3. Извлекаем данные (аналог вашего chat_id и name)
const chatId = item.chat_id;

// Аналог вашего name с цепочкой проверок
const name = item.first_name 
          || item.username
          || "";

// 4. Возвращаем результат в формате n8n
return [{
  json: {
    // Вместо .get() в JS используем логическое ИЛИ для дефолта
    file_name: chatsName[chatId], 
    chat_id: chatId,
    name: name,
    text: item.text
  }
}];

